mapper.select:
select id, code, label, parent_id, node_level, sort_order, is_deleted, created_at, updated_at from industry_sector
is_deleted = 0
AND (code LIKE CONCAT('%', #{keyword}, '%') OR label LIKE CONCAT('%', #{keyword}, '%'))
AND node_level = #{nodeLevel}
AND parent_id = #{parentId}
order by sort_order ASC, id ASC

mapper.update:
update industry_sector
code = #{code}, label = #{label}, parent_id = #{parentId}, node_level = #{nodeLevel}, sort_order = #{sortOrder}, updated_at = NOW()
where id = #{id}
